// ==========================================
// Extract Messenger Event - รองรับ Message, Postback, Referral, Optin
// ==========================================

const body = $input.first().json.body;

if (!body?.entry?.[0]?.messaging?.[0]) {
  return { json: { skip: true, reason: 'invalid' } };
}

const entry = body.entry[0];
const event = entry.messaging[0];

// ==========================================
// 🆕 รองรับ Referral Event (มาจากโฆษณา, โพสต์, คอมเมนต์)
// ==========================================
if (event.referral || event.optin) {
  return {
    json: {
      skip: false,
      senderId: event.sender.id,
      pageId: entry.id,
      text: 'สวัสดี',
      originalText: 'สวัสดี',
      isGreeting: true,     // ← ส่ง Greeting ทันที
      isShowAll: false,
      isQR: false,
      isStorage: false,
      isPostback: false,
      isMessage: true,
      isAdminCommand: false,
      adminCommandType: null,
      timestamp: event.timestamp,
      source: event.referral?.source || event.optin?.ref || 'referral'
    }
  };
}

// ==========================================
// Admin Echo Commands
// ==========================================
const isAdminEcho = event.message?.is_echo === true;
const adminText = isAdminEcho ? (event.message?.text || '').trim() : '';

if (isAdminEcho) {
  let adminCommandType = null;

  if (adminText === '/สรุป') {
    adminCommandType = 'summarize';
  // 🔄 เปลี่ยนจาก /รายการ → สวัสดีครับ / สวัสดีค่ะ
  } else if (adminText === 'สวัสดีครับ' || adminText === 'สวัสดีค่ะ') {
    adminCommandType = 'greeting';
  // 🔄 เปลี่ยนจาก /ทั้งหมด → /สินค้า
  } else if (adminText === '/สินค้า') {
    adminCommandType = 'show_all';
  } else if (adminText === '/qr') {
    adminCommandType = 'qr';
  } else if (adminText === '/เก็บรักษา') {
    adminCommandType = 'storage';
  }

  if (adminCommandType) {
    return {
      json: {
        skip: false,
        senderId: event.recipient.id,
        pageId: entry.id,
        text: adminText,
        originalText: adminText,
        isAdminCommand: true,
        adminCommandType: adminCommandType,
        isGreeting: adminCommandType === 'greeting',
        isShowAll: adminCommandType === 'show_all',
        isQR: adminCommandType === 'qr',
        isStorage: adminCommandType === 'storage',
        isPostback: false,
        isMessage: true,
        timestamp: event.timestamp
      }
    };
  }

  return { json: { skip: true, reason: 'echo_not_command' } };
}

// ==========================================
// Skip system events
// ==========================================
if (event.delivery || event.read) {
  return { json: { skip: true, reason: 'system' } };
}

const isPostback = !!event.postback;
const isMessage = !!event.message;

const rawText = event.message?.text || event.postback?.payload || '';
const text = rawText.trim().toLowerCase();
const originalText = rawText.trim();

if (!text) {
  return { json: { skip: true, reason: 'empty' } };
}

// ==========================================
// 🆕 GET_STARTED Postback → ส่ง Greeting ทันที
// ==========================================
if (event.postback?.payload === 'GET_STARTED') {
  return {
    json: {
      skip: false,
      senderId: event.sender.id,
      pageId: entry.id,
      text: text,
      originalText: originalText,
      isGreeting: true,   // ← ส่ง Greeting ทันที
      isShowAll: false,
      isQR: false,
      isStorage: false,
      isPostback: true,
      isMessage: false,
      isAdminCommand: false,
      adminCommandType: null,
      timestamp: event.timestamp
    }
  };
}

// ==========================================
// Greeting & ShowAll Pattern Matching (เหมือนเดิม)
// ==========================================
const greetingPatterns = [
  'hi', 'hello', 'hey', 'yo',
  'สวัสดี', 'สวัสดีครับ', 'สวัสดีค่ะ', 'สวัสดีคับ', 'สวัสดีจ้า',
  'หวัดดี', 'หวัดดีครับ', 'หวัดดีค่ะ',
  'ดี', 'ดีครับ', 'ดีค่ะ', 'ดีจ้า',
  'ว่าไง', 'ไง', 'เฮ้', 'ฮัลโหล', 'ฮาย',
  'get start', 'get started', 'menu', 'เมนู', 'เริ่ม', 'เริ่มต้น', 'บ้านรวมทะเล'
];

// 🔄 เปลี่ยนจาก /ทั้งหมด → /สินค้า ในส่วนของลูกค้าพิมพ์เอง
const showAllPatterns = [
  'ดูสินค้าทั้งหมด', 'สินค้าทั้งหมด',
  'มีสินค้าอื่นอีกไหม', 'มีสินค้าอื่นไหม',
  'มีอะไรอีก', 'ดูเพิ่ม', 'ดูเพิ่มเติม',
  'show all', 'view all', '/สินค้า'  // ← เพิ่ม /สินค้า
];

function getSimilarity(s1, s2) {
  let longer = s1.length >= s2.length ? s1 : s2;
  let shorter = s1.length < s2.length ? s1 : s2;
  const longerLength = longer.length;
  if (longerLength === 0) return 1.0;
  const costs = new Array();
  for (let i = 0; i <= longer.length; i++) {
    let lastValue = i;
    for (let j = 0; j <= shorter.length; j++) {
      if (i == 0) costs[j] = j;
      else if (j > 0) {
        let newValue = costs[j - 1];
        if (longer.charAt(i - 1) != shorter.charAt(j - 1))
          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
        costs[j - 1] = lastValue;
        lastValue = newValue;
      }
    }
    if (i > 0) costs[shorter.length] = lastValue;
  }
  return (longerLength - costs[shorter.length]) / longerLength;
}

let isGreeting = false;
let isShowAll = false;
const THRESHOLD = 0.75;
const firstWord = text.split(' ')[0];

for (let pattern of greetingPatterns) {
  const scoreFull = getSimilarity(text, pattern);
  const scoreFirstWord = (!pattern.includes(' ')) ? getSimilarity(firstWord, pattern) : 0;
  const isThai = /[ก-๙]/.test(pattern);
  const startsWithThai = isThai && text.startsWith(pattern);
  if (scoreFull >= THRESHOLD || scoreFirstWord >= THRESHOLD || startsWithThai) {
    isGreeting = true;
    break;
  }
}


// QR Payment Pattern Matching
const qrPatterns = ['qr', '/qr', 'สแกนจ่าย', 'สแกน', 'qr code'];
let isQR = false;
for (let pattern of qrPatterns) {
  const score = getSimilarity(text, pattern.toLowerCase());
  if (score >= THRESHOLD || text.includes(pattern.toLowerCase())) {
    isQR = true;
    break;
  }
}

for (let pattern of showAllPatterns) {
  const score = getSimilarity(text, pattern.toLowerCase());
  if (score >= THRESHOLD || text.includes(pattern.toLowerCase())) {
    isShowAll = true;
    break;
  }
}

// Storage Pattern Matching
const storagePatterns = ['เก็บรักษา', 'วิธีเก็บ', 'เก็บยังไง', 'เก็บได้กี่วัน', 'เก็บนานไหม', '/เก็บรักษา'];
let isStorage = false;
for (let pattern of storagePatterns) {
  const score = getSimilarity(text, pattern.toLowerCase());
  if (score >= THRESHOLD || text.includes(pattern.toLowerCase())) {
    isStorage = true;
    break;
  }
}

return {
  json: {
    skip: false,
    senderId: event.sender.id,
    pageId: entry.id,
    text: text,
    originalText: originalText,
    isGreeting: isGreeting,
    isShowAll: isShowAll,
    isQR: isQR,
    isStorage: isStorage,
    isPostback: isPostback,
    isMessage: isMessage,
    isAdminCommand: false,
    adminCommandType: null,
    timestamp: event.timestamp
  }
};
